import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { this.val = v; }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.trim().isEmpty()) return;
        line = line.trim();
        StringTokenizer st = new StringTokenizer(line);
        int T;
        int pendingN = -1, pendingX = -1;
        if (st.countTokens() == 1) {
            // First token is number of test cases
            T = Integer.parseInt(st.nextToken());
        } else {
            // No test case count, treat the line as N X of a single test case
            T = 1;
            pendingN = Integer.parseInt(st.nextToken());
            pendingX = Integer.parseInt(st.nextToken());
        }
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            int N, X;
            if (t == 0 && pendingN != -1) {
                N = pendingN;
                X = pendingX;
            } else {
                // read line containing N and X
                while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
                if (line == null) break;
                st = new StringTokenizer(line);
                N = Integer.parseInt(st.nextToken());
                X = Integer.parseInt(st.nextToken());
            }
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> children = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                // read edge line
                while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
                if (line == null) break;
                st = new StringTokenizer(line);
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                Node parent = map.computeIfAbsent(p, Node::new);
                Node child = map.computeIfAbsent(c, Node::new);
                if (dir == 'L') parent.left = child; else parent.right = child;
                children.add(c);
            }
            // Find root (node that never appears as child)
            Node root = null;
            for (int val : map.keySet()) {
                if (!children.contains(val)) { root = map.get(val); break; }
            }
            // If tree has only one node (N==1) and map may be empty, create root node
            if (N == 1 && root == null) {
                root = new Node(X); // the only node value is X (or could be any, predecessor will be -1)
            }
            Node cur = root;
            Node pred = null;
            while (cur != null) {
                if (cur.val < X) {
                    pred = cur;
                    cur = cur.right;
                } else {
                    cur = cur.left;
                }
            }
            out.append(pred == null ? -1 : pred.val);
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

